import Foundation
import MusicKit

@Observable
class MusicPlaylistViewModel {
    var songs: [Song] = []
    var isAuthorized = false
    var errorMessage: String?
    var playbackState: ApplicationMusicPlayer.PlaybackState = .stopped
    private let player = ApplicationMusicPlayer.shared

    func requestAuthorization() async {
        let status = await MusicAuthorization.request()
        await MainActor.run { isAuthorized = (status == .authorized) }
    }

    func search(term: String) async {
        guard isAuthorized else { return }
        let request = MusicCatalogSearchRequest(term: term, types: [Song.self])
        do {
            let response = try await request.response()
            await MainActor.run { songs = Array(response.songs) }
        } catch {
            await MainActor.run { errorMessage = error.localizedDescription }
        }
    }

    func playSongsForDuration(minutes: Double) async {
        guard isAuthorized, !songs.isEmpty else { return }
        let targetSeconds = minutes * 60
        var total: TimeInterval = 0
        var selected: [Song] = []
        for song in songs {
            if total >= targetSeconds { break }
            selected.append(song)
            total += song.duration ?? 240
        }
        player.queue = ApplicationMusicPlayer.Queue(for: selected)
        try? await player.play()
    }
}
